/* src/pages/Login.js */
import React, { useState } from 'react';
import { Card, Form, Button, Alert, Container } from 'react-bootstrap';
import { useNavigate } from 'react-router-dom';

const Login = () => {
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const navigate = useNavigate();

    const handleLogin = (e) => {
        e.preventDefault();
        // 임시 로직
        if (username === 'admin' && password === '1234') {
            localStorage.setItem('token', 'dummy-token-1234');
            navigate('/');
        } else {
            setError('아이디 admin, 비밀번호 1234를 입력해주세요.');
        }
    };

    const handleGoogleLogin = () => {
        window.location.href = "${process.env.REACT_APP_API_URL}/oauth2/authorization/google";
    };

    return (
        <Container className="d-flex justify-content-center align-items-center" style={{ minHeight: '90vh' }}>
            <Card className="shadow-lg border-0 rounded-5 overflow-hidden" style={{ width: '420px', backgroundColor: '#ffffff' }}>
                {/* 상단 포인트 컬러 바 */}
                <div style={{ height: '8px', backgroundColor: '#ff8a3d' }}></div>
                
                <Card.Body className="p-5">
                    <div className="text-center mb-5">
                        <h2 className="fw-bolder" style={{ color: '#ff8a3d', letterSpacing: '-1px' }}>
                            🥕 ReStock
                        </h2>
                        <p className="text-muted small">스마트한 재고 관리를 시작하세요</p>
                    </div>

                    {error && (
                        <Alert variant="danger" className="py-2 small border-0 rounded-4 text-center mb-4">
                            {error}
                        </Alert>
                    )}

                    <Form onSubmit={handleLogin}>
                        <Form.Group className="mb-3">
                            <Form.Control 
                                type="text" 
                                placeholder="아이디" 
                                className="rounded-pill py-3 px-4 border-0 bg-light shadow-none"
                                style={{ fontSize: '0.9rem' }}
                                value={username}
                                onChange={(e) => setUsername(e.target.value)}
                                required
                            />
                        </Form.Group>

                        <Form.Group className="mb-4">
                            <Form.Control 
                                type="password" 
                                placeholder="비밀번호" 
                                className="rounded-pill py-3 px-4 border-0 bg-light shadow-none"
                                style={{ fontSize: '0.9rem' }}
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                            />
                        </Form.Group>

                        <Button 
                            type="submit" 
                            className="w-100 rounded-pill py-3 fw-bold border-0 shadow-sm mb-4"
                            style={{ backgroundColor: '#ff8a3d', fontSize: '1rem' }}
                        >
                            로그인
                        </Button>

                        <div className="d-flex align-items-center mb-4">
                            <hr className="flex-grow-1 opacity-10" />
                            <span className="mx-3 small text-muted text-nowrap" style={{ fontSize: '0.75rem' }}>소셜 계정으로 로그인</span>
                            <hr className="flex-grow-1 opacity-10" />
                        </div>
                        
                        <Button 
                            variant="white" 
                            className="w-100 rounded-pill py-3 fw-bold d-flex align-items-center justify-content-center shadow-sm border mb-4"
                            style={{ fontSize: '0.9rem', color: '#555' }}
                            onClick={handleGoogleLogin}
                        >
                            <img src="https://upload.wikimedia.org/wikipedia/commons/c/c1/Google_%22G%22_logo.svg" alt="Google" width="18" className="me-2" />
                            Google로 계속하기
                        </Button>
                    </Form>

                    {/* ✅ 카드 내부로 들어온 회원가입 안내 */}
                    <div className="text-center pt-2">
                        <p className="small text-muted mb-0">
                            아직 회원이 아니신가요? {' '}
                            <span 
                                onClick={() => navigate('/signup')} 
                                className="fw-bold text-decoration-none" 
                                style={{ color: '#ff8a3d', cursor: 'pointer' }}
                            >
                                회원가입
                            </span>
                        </p>
                    </div>
                </Card.Body>
            </Card>
        </Container>
    );
};

export default Login;