import React, { useState } from 'react';
import { Card, Form, Button, Alert } from 'react-bootstrap';
import { useNavigate, Link } from 'react-router-dom';

const Signup = () => {
    const navigate = useNavigate();
    const [form, setForm] = useState({ username: '', password: '', confirm: '' });
    const [error, setError] = useState('');

    const handleSignup = (e) => {
        e.preventDefault();
        if(form.password !== form.confirm) return setError('비밀번호가 일치하지 않습니다.');
        alert('회원가입이 완료되었습니다! (임시)');
        navigate('/login');
    };

    return (
        <div className="d-flex justify-content-center align-items-center" style={{ minHeight: '80vh' }}>
            <Card className="shadow-lg border-0 rounded-5 p-4" style={{ width: '400px' }}>
                <Card.Body>
                    <div className="text-center mb-4">
                        <h2 style={{ color: '#ff8a3d', fontWeight: '800' }}>🥕 ReStock 회원가입</h2>
                    </div>
                    {error && <Alert variant="danger" className="small">{error}</Alert>}
                    <Form onSubmit={handleSignup}>
                        <Form.Group className="mb-3">
                            <Form.Label className="small fw-bold px-2">아이디</Form.Label>
                            <Form.Control type="text" className="rounded-pill py-2 bg-light border-0" value={form.username} onChange={e=>setForm({...form, username: e.target.value})} required />
                        </Form.Group>
                        <Form.Group className="mb-3">
                            <Form.Label className="small fw-bold px-2">비밀번호</Form.Label>
                            <Form.Control type="password" className="rounded-pill py-2 bg-light border-0" value={form.password} onChange={e=>setForm({...form, password: e.target.value})} required />
                        </Form.Group>
                        <Form.Group className="mb-4">
                            <Form.Label className="small fw-bold px-2">비밀번호 확인</Form.Label>
                            <Form.Control type="password" className="rounded-pill py-2 bg-light border-0" value={form.confirm} onChange={e=>setForm({...form, confirm: e.target.value})} required />
                        </Form.Group>
                        <Button type="submit" className="w-100 rounded-pill py-3 fw-bold border-0" style={{ backgroundColor: '#ff8a3d' }}>가입하기</Button>
                    </Form>
                    <div className="text-center mt-3"><Link to="/login" className="small text-muted">이미 계정이 있으신가요? 로그인</Link></div>
                </Card.Body>
            </Card>
        </div>
    );
};
export default Signup;
