import React, { useState, useEffect } from 'react';
import { Table, Badge, Card, Row, Col, Alert, Button, Spinner } from 'react-bootstrap';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import AiChat from './AiChat'; 

const API_BASE_URL = process.env.REACT_APP_API_URL;

const Dashboard = () => {
  const [inventory, setInventory] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    axios.get(`${API_BASE_URL}/api/inventory`)
      .then(res => {
        setInventory(res.data);
        setLoading(false);
      })
      .catch(err => {
        console.error("데이터 로딩 실패:", err);
        setLoading(false);
      });
  }, []);

  const getDDay = (expiryDate) => {
    if (!expiryDate) return 999;
    const today = new Date().setHours(0, 0, 0, 0);
    const target = new Date(expiryDate).setHours(0, 0, 0, 0);
    return Math.ceil((target - today) / (1000 * 60 * 60 * 24));
  };

  const expiredItems = inventory.filter(item => item.timeType === 'EXPIRATION' && getDDay(item.expiryDate) < 0);
  const urgentItems = inventory.filter(item => item.timeType === 'EXPIRATION' && getDDay(item.expiryDate) >= 0 && getDDay(item.expiryDate) <= 3);
  const finishedAgingItems = inventory.filter(item => item.timeType === 'AGING' && getDDay(item.expiryDate) <= 0); 
  const processingAgingItems = inventory.filter(item => item.timeType === 'AGING' && getDDay(item.expiryDate) > 0); 
  const totalStock = inventory.reduce((sum, item) => sum + (Number(item.stock) || 0), 0);
  const recentActivities = [...inventory].sort((a, b) => b.id - a.id).slice(0, 5);

  const handleUrlClick = (url) => {
    if (url) {
        const targetUrl = url.startsWith('http') ? url : `https://${url}`;
        window.open(targetUrl, '_blank');
    } else {
        alert('등록된 처리 사이트 URL이 없습니다.');
    }
  };

  if (loading) return <div className="p-5 text-center"><Spinner animation="border" variant="warning" /></div>;

  return (
    <div className="p-4" style={{ backgroundColor: '#fcfcfc', minHeight: '100vh' }}>
      <Row>
        <Col lg={8} xl={9}>
          <h2 className="fw-bold mb-4" style={{ color: '#ff8a3d' }}>📊 재고 관제 센터</h2>

          <div className="mb-4">
            {expiredItems.length > 0 && (
              <Alert variant="dark" className="border-0 shadow-sm rounded-4 mb-3 d-flex justify-content-between align-items-center p-4">
                <div>
                  <h5 className="fw-bold mb-1">💀 즉시 폐기/정리 필요 ({expiredItems.length}건)</h5>
                  <span className="small">유통기한이 지나 손실이 발생했습니다. 즉시 정리 사이트로 이동하세요.</span>
                </div>
                <Button variant="light" className="fw-bold px-4 rounded-pill shadow-sm" onClick={() => navigate('/inventory')}>목록 확인</Button>
              </Alert>
            )}
            <Row className="g-3">
              {urgentItems.length > 0 && (
                <Col lg={6}><Alert variant="danger" className="border-0 shadow-sm rounded-4 h-100 p-3"><h6 className="fw-bold mb-1">🚨 유통기한 임박 ({urgentItems.length}건)</h6></Alert></Col>
              )}
              {finishedAgingItems.length > 0 && (
                <Col lg={6}><Alert variant="success" className="border-0 shadow-sm rounded-4 h-100 p-3"><h6 className="fw-bold mb-1">✨ 숙성 완료 알림 ({finishedAgingItems.length}건)</h6></Alert></Col>
              )}
            </Row>
          </div>

          <Row className="mb-4 g-4 text-center">
            <Col xs={6} md={3}>
              <div className="p-4 rounded-4 shadow-sm bg-white border h-100">
                <h6 className="text-muted small fw-bold">전체 관리 품목</h6>
                <h2 className="fw-bold mb-0">{inventory.length} <small style={{fontSize: '14px', color: '#999'}}>({totalStock}개)</small></h2>
              </div>
            </Col>
            <Col xs={6} md={3}>
              <div className="p-4 rounded-4 shadow-sm bg-white border h-100">
                <h6 className="text-danger small fw-bold">폐기/임박 주의</h6>
                <h2 className="fw-bold mb-0 text-danger">{expiredItems.length + urgentItems.length}</h2>
              </div>
            </Col>
            <Col xs={6} md={3}>
              <div className="p-4 rounded-4 shadow-sm bg-white border border-primary h-100">
                <h6 className="text-primary small fw-bold">현재 숙성 중</h6>
                <h2 className="fw-bold mb-0 text-primary">{processingAgingItems.length}</h2>
              </div>
            </Col>
            <Col xs={6} md={3}>
              <div className="p-4 rounded-4 shadow-sm text-white h-100" style={{ backgroundColor: finishedAgingItems.length > 0 ? '#198754' : '#6c757d' }}>
                <h6 className="opacity-75 small fw-bold">✨ 숙성 완료</h6>
                <h2 className="fw-bold mb-0">{finishedAgingItems.length}</h2>
              </div>
            </Col>
          </Row>

          <Card className="border-0 shadow-sm rounded-4 overflow-hidden mb-5">
            <Card.Header className="bg-white border-0 pt-4 pb-0 d-flex justify-content-between align-items-center">
              <h5 className="fw-bold mb-0 text-muted">최근 입고된 품목</h5>
              <Button variant="link" className="text-decoration-none text-muted p-0" onClick={() => navigate('/inventory')}>전체보기 ›</Button>
            </Card.Header>
            <Card.Body className="p-0 mt-3">
              <Table hover responsive className="m-0 align-middle text-center">
                <thead className="table-light">
                  <tr className="small text-muted">
                    <th className="ps-4 text-start">품목 상세</th>
                    <th>상태</th>
                    <th>액션</th>
                  </tr>
                </thead>
                <tbody>
                  {recentActivities.map(item => (
                    <tr key={item.id}>
                      <td className="ps-4 text-start">
                        <div className="d-flex align-items-center gap-3">
                          <img src={item.imageUrl ? `${API_BASE_URL}${item.imageUrl}` : "https://via.placeholder.com/50"} className="rounded-3" style={{ width: '40px', height: '40px', objectFit: 'cover' }} alt="" />
                          <div><div className="fw-bold small">{item.name}</div><small className="text-muted">{item.stock}개</small></div>
                        </div>
                      </td>
                      <td><Badge bg={getDDay(item.expiryDate) <= 3 ? "danger" : "info"}>D-{getDDay(item.expiryDate)}</Badge></td>
                      <td><Button variant="primary" size="sm" className="rounded-pill px-3 shadow-sm" onClick={() => handleUrlClick(item.customUrl)}>🚀 처분</Button></td>
                    </tr>
                  ))}
                </tbody>
              </Table>
            </Card.Body>
          </Card>
        </Col>

        <Col lg={4} xl={3}>
          <div className="sticky-top" style={{ top: '20px' }}>
            <AiChat />
          </div>
        </Col>
      </Row>
    </div>
  );
};

export default Dashboard;