import React, { useState } from 'react';
import { Card, Form, Button } from 'react-bootstrap';
import { useNavigate } from 'react-router-dom';

const Profile = () => {
    const navigate = useNavigate();
    const [name, setName] = useState('관리자');

    const handleUpdate = () => {
        alert('내 정보가 수정되었습니다!');
    };

    const handleDeleteAccount = () => {
        if (window.confirm('정말 탈퇴하시겠습니까? (창고 시스템 권한이 모두 사라집니다)')) {
            localStorage.removeItem('token');
            alert('회원 탈퇴가 완료되었습니다.');
            navigate('/login');
        }
    };

    return (
        <div className="p-4" style={{ backgroundColor: '#fcfcfc', minHeight: '80vh' }}>
            <h3 className="fw-bold mb-4">⚙️ 계정 관리 (내 정보 / 회원 탈퇴)</h3>
            <Card className="shadow-sm border-0 rounded-5 p-4" style={{ maxWidth: '500px' }}>
                <Card.Body>
                    <Form.Group className="mb-4">
                        <Form.Label className="fw-bold px-2">이름(닉네임)</Form.Label>
                        <Form.Control type="text" className="rounded-pill py-2 bg-light border-0" value={name} onChange={e=>setName(e.target.value)} />
                    </Form.Group>
                    <Button variant="primary" className="w-100 rounded-pill py-3 fw-bold border-0 mb-4" onClick={handleUpdate}>정보 수정 완료</Button>
                    <hr className="text-muted" />
                    <div className="text-center mt-4">
                        <Button variant="outline-danger" className="rounded-pill w-100" onClick={handleDeleteAccount}>🚨 회원 탈퇴하기</Button>
                        <p className="small text-muted mt-2">탈퇴 시 모든 데이터가 삭제되며 되돌릴 수 없습니다.</p>
                    </div>
                </Card.Body>
            </Card>
        </div>
    );
};
export default Profile;
