import { configureStore, createSlice } from '@reduxjs/toolkit';

// 1. 재고 관리 슬라이스
const inventory = createSlice({
  name: 'inventory',
  initialState: [
    { 
      id: 1, name: "세척당근", category: "채소", stock: 150, location: "A-1", 
      qr: "QR-101", img: "https://images.unsplash.com/photo-1598170845058-32b9d6a5da37?w=300", 
      weight: "10kg", size: "중형", expiryDate: "2026-03-01", status: "정상",
      serviceName: "푸드뱅크", serviceUrl: "https://www.foodbank1377.org/" 
    }
  ],
  reducers: {
    addItem(state, action) {
      state.push(action.payload);
    },
    updateItem(state, action) {
      const idx = state.findIndex(i => i.id === action.payload.id);
      if (idx !== -1) {
        const item = { ...action.payload };
        const today = new Date();
        const expiry = new Date(item.expiryDate);
        const diffDays = Math.ceil((expiry - today) / (1000 * 60 * 60 * 24));
        
        if (diffDays < 0) item.status = "폐기/긴급";
        else if (diffDays <= 3) item.status = "기부";
        else if (diffDays <= 7) item.status = "나눔/할인";
        else item.status = "정상";
        
        state[idx] = item;
      }
    },
    deleteItem(state, action) {
      return state.filter(i => i.id !== action.payload);
    }
  }
});

// 2. 카테고리 관리 슬라이스
const categories = createSlice({
  name: 'categories',
  initialState: ["채소", "과일", "곡류", "가공식품"],
  reducers: {
    addCategory(state, action) {
      if(!state.includes(action.payload)) state.push(action.payload);
    }
  }
});

// 3. 처리 사이트 관리 슬라이스 (신설)
const services = createSlice({
  name: 'services',
  initialState: [
    { id: 1, name: '푸드뱅크', url: 'https://www.foodbank1377.org/', type: '기부' },
    { id: 2, name: '당근마켓', url: 'https://www.daangn.com/', type: '나눔' },
    { id: 3, name: '빼기(폐기)', url: 'https://www.bbegi.com/', type: '폐기' }
  ],
  reducers: {
    addService(state, action) {
      state.push(action.payload);
    },
    deleteService(state, action) {
      return state.filter(s => s.id !== action.payload);
    }
  }
});

export const { addItem, updateItem, deleteItem } = inventory.actions;
export const { addCategory } = categories.actions;
export const { addService, deleteService } = services.actions;

export default configureStore({
  reducer: {
    inventory: inventory.reducer,
    categories: categories.reducer,
    services: services.reducer
  }
});