import React, { useState, useEffect, useRef } from 'react';
import { Container, Row, Col, Card, Form, Button, ButtonGroup, Badge, Spinner, ProgressBar } from 'react-bootstrap';
import { useNavigate, useParams } from 'react-router-dom';
import axios from 'axios';

const InventoryEdit = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    
    const API_BASE_URL = process.env.REACT_APP_API_URL || ""; 
    const qrRef = useRef(null);

    const [item, setItem] = useState({
        name: '', stock: 0, status: '정상', category: '', location: '',
        description: '', timeType: 'EXPIRATION', referenceDate: '', expiryDate: '', 
        serviceName: '', customUrl: '', autoDelete: false, qrCodeData: '', imageUrl: ''
    });
    
    const [serviceList, setServiceList] = useState([]); 
    const [loading, setLoading] = useState(true);
    const [isUpdating, setIsUpdating] = useState(false);
    const [daysToAdd, setDaysToAdd] = useState(""); 

    const categories = JSON.parse(localStorage.getItem('restock_cats') || "[]");
    const locations = JSON.parse(localStorage.getItem('restock_locs') || "[]");

    // 1. 데이터 로드 (핵심: 기존 저장된 서비스 정보가 있으면 이를 유지)
    useEffect(() => {
        const fetchData = async () => {
            try {
                const [itemRes, serviceRes] = await Promise.all([
                    axios.get(`${API_BASE_URL}/api/inventory/${id}`),
                    axios.get(`${API_BASE_URL}/api/services`) 
                ]);

                if (itemRes.data) {
                    const data = itemRes.data;
                    setItem({
                        ...data,
                        // 기존 DB에 저장된 serviceName과 customUrl이 있다면 그대로 가져옴
                        serviceName: data.serviceName || '', 
                        customUrl: data.customUrl || '',
                        referenceDate: data.referenceDate ? data.referenceDate.split('T')[0] : '',
                        expiryDate: data.expiryDate ? data.expiryDate.split('T')[0] : ''
                    });
                }
                setServiceList(serviceRes.data || []);
            } catch (error) {
                console.error("데이터 로드 실패:", error);
                alert("항목 정보를 불러오는 데 실패했습니다.");
                navigate('/inventory');
            } finally { setLoading(false); }
        };
        fetchData();
    }, [id, navigate, API_BASE_URL]);

    // 2. QR 코드 렌더링
    useEffect(() => {
        if (!loading && item.qrCodeData && qrRef.current && window.QRCode) {
            qrRef.current.innerHTML = "";
            new window.QRCode(qrRef.current, { 
                text: item.qrCodeData, 
                width: 140, 
                height: 140,
                correctLevel: window.QRCode.CorrectLevel.H 
            });
        }
    }, [item.qrCodeData, loading]);

    // 3. 숙성 일수 자동 계산
    useEffect(() => {
        if (item.timeType === 'AGING' && daysToAdd) {
            const refDate = new Date(item.referenceDate || new Date());
            refDate.setDate(refDate.getDate() + parseInt(daysToAdd));
            setItem(prev => ({ ...prev, expiryDate: refDate.toISOString().split('T')[0] }));
        }
    }, [daysToAdd, item.timeType, item.referenceDate]);

    // 4. 진행률 및 남은 일수 계산
    const getAgingProgress = () => {
        if (!item.referenceDate || !item.expiryDate) return 0;
        const start = new Date(item.referenceDate).getTime();
        const end = new Date(item.expiryDate).getTime();
        const now = new Date().getTime();
        if (now < start) return 0;
        if (now > end) return 100;
        return Math.round(((now - start) / (end - start)) * 100);
    };

    const getRemainingDays = () => {
        if (!item.expiryDate) return 0;
        const diff = new Date(item.expiryDate) - new Date();
        return Math.ceil(diff / (1000 * 60 * 60 * 24));
    };

    // 5. 서비스 선택 핸들러 (선택 시 자동 입력 + if 조건 강화)
    const handleServiceChange = (e) => {
        const selectedUrl = e.target.value;
        
        // 아무것도 선택 안 했을 때 (초기화 방지 로직 필요시 수정)
        if (!selectedUrl) {
            setItem(prev => ({ ...prev, serviceName: '', customUrl: '' }));
            return;
        }

        const selectedService = serviceList.find(s => s.url === selectedUrl);
        
        // 만약 리스트에 있는 서비스를 선택했다면 해당 정보로 필드 업데이트
        if (selectedService) {
            setItem(prev => ({ 
                ...prev, 
                serviceName: selectedService.name, 
                customUrl: selectedService.url 
            }));
        }
    };

    // 6. 데이터 보정(수정) 저장
    const handleUpdate = async () => {
        if (!item.name) return alert("품목명은 필수입니다.");
        setIsUpdating(true);
        try {
            // 보정된 serviceName과 customUrl이 item 객체에 담겨 전송됨
            await axios.put(`${API_BASE_URL}/api/inventory/${id}`, item);
            alert("재고 정보가 성공적으로 보정되었습니다! 🥕");
            navigate('/inventory');
        } catch (error) {
            console.error("저장 오류:", error);
            alert(`저장 실패: ${error.response?.data?.message || error.message}`);
        } finally { setIsUpdating(false); }
    };

    if (loading) return <div className="p-5 text-center"><Spinner animation="border" variant="warning" /></div>;

    return (
        <Container className="py-5" style={{maxWidth: '1100px'}}>
            <div className="d-flex justify-content-between align-items-center mb-4">
                <div className="d-flex align-items-center gap-3">
                    <Button variant="white" className="rounded-circle shadow-sm border" onClick={() => navigate(-1)}>←</Button>
                    <h3 className="fw-bold m-0" style={{color: '#333'}}>재고 실사 및 데이터 보정</h3>
                </div>
                <Button variant="outline-danger" className="rounded-pill px-4 fw-bold shadow-sm" onClick={async () => {
                    if(window.confirm("이 항목을 영구 삭제하시겠습니까?")) {
                        await axios.delete(`${API_BASE_URL}/api/inventory/${id}`);
                        navigate('/inventory');
                    }
                }}>🗑️ 영구 삭제</Button>
            </div>

            <Row className="g-4">
                <Col lg={4}>
                    <Card className="border-0 shadow-sm rounded-5 p-4 text-center sticky-top" style={{top: '20px'}}>
                        <div className="mb-3 position-relative">
                            <img src={item.imageUrl ? (item.imageUrl.startsWith('http') ? item.imageUrl : `${API_BASE_URL}${item.imageUrl}`) : '/default.png'} 
                                 className="rounded-4 w-100 border shadow-sm" style={{height:'300px', objectFit:'cover'}} alt="품목" 
                                 onError={(e) => { e.target.src = "https://via.placeholder.com/300?text=No+Image"; }} />
                            <Badge bg={item.status === '폐기' ? 'danger' : item.status === '파손' ? 'warning' : 'success'} 
                                   className={`position-absolute top-0 end-0 m-3 px-3 py-2 shadow text-${item.status === '파손' ? 'dark' : 'white'}`}>
                                {item.status}
                            </Badge>
                        </div>
                        <div ref={qrRef} className="d-inline-block p-2 bg-white border mx-auto mb-2 rounded-3 shadow-sm"></div>
                        <p className="small text-muted fw-bold mb-0">QR 식별값: {item.qrCodeData}</p>
                    </Card>
                </Col>

                <Col lg={8}>
                    <Card className="border-0 shadow-sm rounded-5 p-4 p-md-5 bg-white">
                        {item.timeType === 'AGING' && (
                            <div className="mb-4 p-4 rounded-4" style={{backgroundColor: '#f0f7ff', border: '1px solid #cfe2ff'}}>
                                <div className="d-flex justify-content-between align-items-center mb-2">
                                    <span className="fw-bold text-primary">🍶 숙성 진행도</span>
                                    <span className="fw-bold text-primary">{getAgingProgress()}%</span>
                                </div>
                                <ProgressBar animated now={getAgingProgress()} variant="primary" style={{height: '15px', borderRadius: '10px'}} />
                                <p className="text-center small text-muted mt-2 mb-0">
                                    {getAgingProgress() >= 100 ? "✅ 숙성 완료되었습니다!" : `완료까지 ${getRemainingDays()}일 남았습니다.`}
                                </p>
                            </div>
                        )}

                        <Row className="g-4 mb-4">
                            <Col md={8}>
                                <Form.Label className="fw-bold text-secondary">품목명</Form.Label>
                                <Form.Control className="rounded-4 py-2 shadow-sm border-0 bg-light" value={item.name || ''} onChange={e => setItem({...item, name: e.target.value})} />
                            </Col>
                            <Col md={4}>
                                <Form.Label className="fw-bold text-secondary">현재 수량</Form.Label>
                                <Form.Control type="number" className="rounded-4 py-2 shadow-sm border-0 bg-light text-center fw-bold" value={item.stock || 0} onChange={e => setItem({...item, stock: e.target.value})} />
                            </Col>
                        </Row>

                        <div className="mb-4">
                            <Form.Label className="fw-bold mb-3 text-secondary">실사 상태 보정</Form.Label>
                            <div className="d-flex gap-2">
                                {['정상', '파손', '폐기'].map((s) => (
                                    <Button key={s} variant={item.status === s ? (s==='정상'?'success':s==='파손'?'warning':'danger') : 'outline-secondary'}
                                        className={`flex-grow-1 rounded-pill fw-bold ${item.status === s && s === '파손' ? 'text-dark' : ''}`}
                                        onClick={() => setItem({...item, status: s})}> {s} </Button>
                                ))}
                            </div>
                        </div>

                        <Row className="g-4 mb-4">
                            <Col md={6}>
                                <Form.Label className="fw-bold text-secondary">카테고리</Form.Label>
                                <Form.Select className="rounded-4 py-2 shadow-sm border-0 bg-light" value={item.category || ""} onChange={e => setItem({...item, category: e.target.value})}>
                                    <option value="" disabled>선택</option>
                                    {categories.map(c => <option key={c} value={c}>{c}</option>)}
                                </Form.Select>
                            </Col>
                            <Col md={6}>
                                <Form.Label className="fw-bold text-secondary">보관 위치</Form.Label>
                                <Form.Select className="rounded-4 py-2 shadow-sm border-0 bg-light" value={item.location || ""} onChange={e => setItem({...item, location: e.target.value})}>
                                    <option value="" disabled>선택</option>
                                    {locations.map(l => <option key={l} value={l}>{l}</option>)}
                                </Form.Select>
                            </Col>
                        </Row>

                        <div className="p-4 rounded-5 mb-4" style={{ backgroundColor: '#fff8f4', border: '1px solid #ffe0cc' }}>
                            <div className="d-flex justify-content-between align-items-center mb-3">
                                <h6 className="fw-bold m-0">⏰ 기한 설정 보정</h6>
                                <ButtonGroup size="sm">
                                    {['EXPIRATION', 'AGING'].map((type) => (
                                        <Button key={type} variant={item.timeType === type ? 'dark' : 'outline-dark'} 
                                            onClick={() => { setItem({...item, timeType: type}); setDaysToAdd(""); }} 
                                            className="px-3 rounded-pill ms-1 text-uppercase">
                                            {type === 'EXPIRATION' ? '유통기한' : '숙성'}
                                        </Button>
                                    ))}
                                </ButtonGroup>
                            </div>
                            <Row className="g-3">
                                <Col md={4}><Form.Control type="date" className="py-2 rounded-3 border-0 shadow-sm" value={item.referenceDate || ''} onChange={e => setItem({...item, referenceDate: e.target.value})} /></Col>
                                {item.timeType === 'AGING' && (
                                    <Col md={4}><Form.Control type="number" placeholder="일수" className="py-2 rounded-3 border-0 shadow-sm text-primary fw-bold" value={daysToAdd} onChange={e => setDaysToAdd(e.target.value)} /></Col>
                                )}
                                <Col md={item.timeType === 'AGING' ? 4 : 8}><Form.Control type="date" className="py-2 rounded-3 border-0 shadow-sm" value={item.expiryDate || ''} onChange={e => setItem({...item, expiryDate: e.target.value})} readOnly={item.timeType === 'AGING'} /></Col>
                            </Row>
                        </div>

                        {/* 외부 서비스 연동 보정 섹션 (핵심 수정 부분) */}
                        <div className="mb-4 p-4 rounded-4" style={{ backgroundColor: '#f8f9fa', border: '1px solid #e9ecef' }}>
                            <Form.Label className="fw-bold mb-3 text-secondary">🔗 외부 서비스 연동 보정</Form.Label>
                            
                            {/* 현재 DB에 저장된 URL과 리스트의 URL이 일치하면 해당 옵션이 선택됨 */}
                            <Form.Select 
                                className="mb-3 rounded-4 py-2 shadow-sm border-0" 
                                value={serviceList.some(s => s.url === item.customUrl) ? item.customUrl : ""} 
                                onChange={handleServiceChange}
                            >
                                <option value="">등록된 처리 사이트 선택</option>
                                {serviceList.map(s => (
                                    <option key={s.id} value={s.url}>[{s.type}] {s.name}</option>
                                ))}
                            </Form.Select>

                            <div className="d-flex gap-2">
                                <div className="w-50">
                                    <Form.Label className="small text-muted ps-2">기관/업체명 (수정 가능)</Form.Label>
                                    <Form.Control 
                                        className="rounded-4 py-2 shadow-sm border-0 bg-white" 
                                        value={item.serviceName || ''} 
                                        onChange={e => setItem({...item, serviceName: e.target.value})} 
                                        placeholder="기관명을 입력하세요"
                                    />
                                </div>
                                <div className="w-50">
                                    <Form.Label className="small text-muted ps-2">URL (수정 가능)</Form.Label>
                                    <Form.Control 
                                        className="rounded-4 py-2 shadow-sm border-0 bg-white" 
                                        value={item.customUrl || ''} 
                                        onChange={e => setItem({...item, customUrl: e.target.value})} 
                                        placeholder="https://..."
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="px-2 mb-4">
                            <Form.Check type="switch" id="auto-delete-edit" label="기한 만료 시 자동 삭제 (권장)" className="fw-bold text-danger mb-3" checked={item.autoDelete || false} onChange={e => setItem({...item, autoDelete: e.target.checked})} />
                            <Form.Control as="textarea" rows={3} className="rounded-4 bg-light border-0 p-3 shadow-sm" placeholder="특이사항 메모" value={item.description || ''} onChange={e => setItem({...item, description: e.target.value})} />
                        </div>

                        <Button style={{backgroundColor: '#ff8a3d'}} className="w-100 text-white border-0 fw-bold shadow-lg rounded-pill py-3" onClick={handleUpdate} disabled={isUpdating}>
                            {isUpdating ? <Spinner animation="border" size="sm" /> : "수정 내용 저장 및 보정 완료"}
                        </Button>
                    </Card>
                </Col>
            </Row>
        </Container>
    );
};

export default InventoryEdit;