import React, { useState, useEffect, useCallback } from 'react';
import { Row, Col, Card, Badge, Form, Button, Table, InputGroup, Container } from 'react-bootstrap';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import AiChat from './AiChat'; // 👈 AI 챗봇 컴포넌트 임포트 확인

const Inventory = () => {
    const navigate = useNavigate();
    const API_BASE_URL = process.env.REACT_APP_API_URL || ""; 
    
    const [inventory, setInventory] = useState([]);
    const [filteredItems, setFilteredItems] = useState([]);
    const [viewMode, setViewMode] = useState('grid'); 
    const [searchTerm, setSearchTerm] = useState("");
    
    const [statusFilter, setStatusFilter] = useState("ALL");
    const [categoryFilter, setCategoryFilter] = useState("ALL");
    const categories = JSON.parse(localStorage.getItem('restock_cats') || "[]");

    const fetchData = useCallback(async () => {
        try {
            const response = await axios.get(`${API_BASE_URL}/api/inventory`);
            setInventory(response.data);
            setFilteredItems(response.data);
        } catch (error) { 
            console.error("데이터 로드 실패:", error); 
        }
    }, [API_BASE_URL]);

    useEffect(() => { fetchData(); }, [fetchData]);

    useEffect(() => {
        let result = inventory.filter(item => 
            (item.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
             item.location?.toLowerCase().includes(searchTerm.toLowerCase()))
        );
        if (statusFilter !== "ALL") result = result.filter(item => item.status === statusFilter);
        if (categoryFilter !== "ALL") result = result.filter(item => item.category === categoryFilter);
        setFilteredItems(result);
    }, [searchTerm, statusFilter, categoryFilter, inventory]);

    const handleUrlClick = (e, url) => {
        e.stopPropagation();
        if (url) {
            const targetUrl = url.startsWith('http') ? url : `https://${url}`;
            window.open(targetUrl, '_blank');
        }
    };

    const renderDDayBadge = (item) => {
        const { expiryDate, timeType } = item;
        if (!expiryDate) return <Badge bg="secondary" style={{fontSize: '0.7rem'}}>기한없음</Badge>;
        const diff = Math.ceil((new Date(expiryDate).setHours(0,0,0,0) - new Date().setHours(0,0,0,0)) / (1000*60*60*24));
        
        if (timeType === 'AGING') {
            return <Badge bg={diff > 0 ? "primary" : "success"} className="rounded-pill px-2 shadow-sm" style={{fontSize: '0.7rem'}}>
                {diff > 0 ? `🧪 숙성 D-${diff}` : `✨ 숙성 완료`}
            </Badge>;
        }
        return <Badge bg={diff < 0 ? "dark" : diff <= 3 ? "danger" : "info"} className="rounded-pill px-2 text-white shadow-sm" style={{fontSize: '0.7rem'}}>
            D-{diff < 0 ? '만료' : diff === 0 ? 'Day' : diff}
        </Badge>;
    };

    return (
        <Container fluid className="p-4" style={{ backgroundColor: '#fcfcfc', minHeight: '100vh' }}>
            <Row>
                {/* 👈 좌측: 기존 재고 관리 영역 (8/12 비율) */}
                <Col lg={8} xl={9}>
                    {/* 상단 헤더 & 검색 */}
                    <div className="d-flex flex-wrap justify-content-between align-items-center mb-3 bg-white p-4 rounded-5 shadow-sm border border-light">
                        <div onClick={() => navigate('/')} style={{ cursor: 'pointer' }}>
                            <h3 className="fw-bold m-0" style={{ color: '#ff8a3d' }}>ReStock <span className="text-dark">Inventory</span></h3>
                        </div>
                        <div className="d-flex gap-2 align-items-center">
                            <InputGroup className="shadow-sm rounded-pill overflow-hidden border-0" style={{ maxWidth: '250px' }}>
                                <Form.Control placeholder="품목명, 위치 검색..." className="bg-light border-0" onChange={e => setSearchTerm(e.target.value)} />
                            </InputGroup>
                            <div className="bg-light p-1 rounded-4 d-flex gap-1 shadow-sm">
                                <Button variant={viewMode === 'grid' ? 'white' : 'transparent'} className="border-0 rounded-4" onClick={() => setViewMode('grid')}>▦</Button>
                                <Button variant={viewMode === 'list' ? 'white' : 'transparent'} className="border-0 rounded-4" onClick={() => setViewMode('list')}>〓</Button>
                            </div>
                        </div>
                    </div>

                    {/* 상태 필터 버튼 */}
                    <div className="d-flex gap-2 mb-3 overflow-auto pb-2">
                        {['ALL', '정상', '파손', '폐기'].map(status => (
                            <Button 
                                key={status}
                                variant={statusFilter === status ? (status === '파손' ? 'warning' : status === '폐기' ? 'danger' : status === '정상' ? 'success' : 'dark') : 'outline-secondary'}
                                className={`rounded-pill px-4 fw-bold shadow-sm border-0 ${statusFilter === status && status === '파손' ? 'text-dark' : ''}`}
                                onClick={() => setStatusFilter(status)}
                            >
                                {status === 'ALL' ? '전체상태' : status}
                            </Button>
                        ))}
                    </div>

                    {/* 카테고리 필터 버튼 */}
                    <div className="d-flex gap-2 mb-4 overflow-auto pb-2">
                        <Button 
                            variant={categoryFilter === 'ALL' ? 'primary' : 'light'} 
                            className="rounded-pill px-3 shadow-sm border-0 fw-bold"
                            onClick={() => setCategoryFilter('ALL')}
                        ># 전체</Button>
                        {categories.map(cat => (
                            <Button key={cat} variant={categoryFilter === cat ? 'primary' : 'light'} className="rounded-pill px-3 shadow-sm border-0 fw-bold" onClick={() => setCategoryFilter(cat)}># {cat}</Button>
                        ))}
                    </div>

                    {viewMode === 'grid' ? (
                        <Row className="g-3">
                            {/* 신규 등록 카드 */}
                            <Col xs={6} md={4} lg={3}>
                                <div style={{ width: '100%', aspectRatio: '1/1' }}>
                                    <Card className="w-100 h-100 border-0 shadow-sm rounded-5 overflow-hidden" style={{ cursor: 'pointer' }} onClick={() => navigate('/inbound')}>
                                        <div className="d-flex flex-column align-items-center justify-content-center text-center w-100 h-100" style={{ background: 'linear-gradient(135deg, #ff8a3d 0%, #ff6b3d 100%)', color: 'white' }}>
                                            <div className="display-4 fw-lighter mb-1">+</div>
                                            <p className="fw-bold m-0" style={{ fontSize: '0.9rem' }}>신규 등록</p>
                                        </div>
                                    </Card>
                                </div>
                            </Col>

                            {/* 재고 카드 리스트 */}
                            {filteredItems.map(item => (
                                <Col key={item.id} xs={6} md={4} lg={3}>
                                    <Card className="h-100 border-0 shadow-sm rounded-5 overflow-hidden d-flex flex-column shadow-hover" onClick={() => navigate(`/inventory/edit/${item.id}`)} style={{ cursor:'pointer' }}>
                                        <div style={{ width: '100%', aspectRatio: '1/1', position: 'relative', overflow: 'hidden', backgroundColor: '#f8f9fa' }}>
                                            <img src={`${API_BASE_URL}${item.imageUrl}`} className="w-100 h-100 object-fit-cover" alt="" onError={(e) => { e.target.src = "/default.png"; }} />
                                            <div className="position-absolute top-0 end-0 m-2">{renderDDayBadge(item)}</div>
                                            <Badge bg={item.status === '파손' ? 'warning' : item.status === '폐기' ? 'danger' : 'success'} className={`position-absolute bottom-0 start-0 m-2 px-2 py-1 text-${item.status === '파손' ? 'dark' : 'white'}`} style={{ fontSize: '0.65rem' }}>{item.status}</Badge>
                                        </div>
                                        <Card.Body className="p-2 text-center d-flex flex-column justify-content-between flex-grow-1">
                                            <div>
                                                <h6 className="fw-bold text-truncate mb-0" style={{ fontSize: '0.85rem' }}>{item.name}</h6>
                                                <div className="text-muted mb-2" style={{ fontSize: '0.75rem' }}>{item.stock}개 | {item.location}</div>
                                            </div>
                                            {item.customUrl && (
                                                <Button variant="dark" className="w-100 py-1 rounded-4 border-0 mt-auto" style={{ fontSize: '0.7rem', fontWeight: '600' }} onClick={(e) => handleUrlClick(e, item.customUrl)}>
                                                    🚀 {item.serviceName || '연동'}
                                                </Button>
                                            )}
                                        </Card.Body>
                                    </Card>
                                </Col>
                            ))}
                        </Row>
                    ) : (
                        /* 리스트 모드 (생략 없이 유지) */
                        <Card className="border-0 shadow-sm rounded-5 overflow-hidden">
                            <Table hover responsive className="m-0 align-middle text-center">
                                <thead className="bg-light">
                                    <tr><th>사진</th><th>품목명</th><th>상태</th><th>분류</th><th>수량</th><th>기한</th><th>연동</th></tr>
                                </thead>
                                <tbody>
                                    {filteredItems.map(item => (
                                        <tr key={item.id} onClick={() => navigate(`/inventory/edit/${item.id}`)} style={{ cursor: 'pointer' }}>
                                            <td><img src={`${API_BASE_URL}${item.imageUrl}`} width="40" height="40" className="rounded-3 object-fit-cover" alt="" /></td>
                                            <td className="fw-bold">{item.name}</td>
                                            <td><Badge bg={item.status === '파손' ? 'warning' : item.status === '폐기' ? 'danger' : 'success'}>{item.status}</Badge></td>
                                            <td>{item.category}</td>
                                            <td className="fw-bold" style={{color: '#ff8a3d'}}>{item.stock}개</td>
                                            <td>{renderDDayBadge(item)}</td>
                                            <td>{item.customUrl && <Button size="sm" variant="outline-dark" className="rounded-pill" onClick={(e) => handleUrlClick(e, item.customUrl)}>🚀</Button>}</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </Table>
                        </Card>
                    )}
                </Col>

                {/* 👈 우측: AI 비서 채팅 영역 (4/12 비율) */}
                <Col lg={4} xl={3}>
                    <div className="sticky-top" style={{ top: '24px', height: 'calc(100vh - 48px)' }}>
                        <AiChat />
                    </div>
                </Col>
            </Row>
        </Container>
    );
};

export default Inventory;