import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Card, Button, Form, InputGroup, Spinner } from 'react-bootstrap';

// ✅ 환경 변수가 없을 경우를 대비해 백엔드 주소(8080)를 명시적으로 설정합니다.
const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:8080';

const AiChat = () => {
    const [messages, setMessages] = useState([
        { id: 1, sender: 'ai', text: '안녕하세요! 재고 관리 비서입니다. 궁금한 품목의 유통기한이나 수량을 물어보세요! 🥕' }
    ]);
    const [input, setInput] = useState('');
    const [isRecording, setIsRecording] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const recognitionRef = useRef(null);
    const scrollRef = useRef(null);

    // 자동 스크롤: 메시지가 추가될 때마다 최하단으로 이동
    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages, isLoading]);

    // 음성 인식 설정 (Web Speech API)
    useEffect(() => {
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        if (SpeechRecognition) {
            const recognition = new SpeechRecognition();
            recognition.lang = 'ko-KR';
            recognition.interimResults = true; 
            
            recognition.onresult = (e) => {
                const transcript = e.results[0][0].transcript;
                setInput(transcript);
            };
            recognition.onerror = () => setIsRecording(false);
            recognition.onend = () => setIsRecording(false);
            recognitionRef.current = recognition;
        }
        return () => recognitionRef.current && recognitionRef.current.abort();
    }, []);

    const toggleRecording = useCallback(() => {
        if (!recognitionRef.current) return alert('마이크를 지원하지 않습니다.');
        if (isRecording) {
            recognitionRef.current.stop();
        } else {
            recognitionRef.current.start();
            setIsRecording(true);
        }
    }, [isRecording]);

    const handleSend = async (e) => {
        e?.preventDefault();
        const msgText = input.trim();
        if (!msgText || isLoading) return;

        // 1. 사용자가 보낸 메시지 화면에 즉시 추가
        setMessages(prev => [...prev, { id: Date.now(), sender: 'user', text: msgText }]);
        setInput('');
        setIsLoading(true);

        try {
            // 2. 백엔드(Spring Boot) 컨트롤러로 질문 전달
            // 주소: http://localhost:8080/api/chat/ask
            const res = await fetch(`${API_BASE_URL}/api/chat/ask`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ message: msgText }),
                credentials: 'include' 
            });
            
            if (!res.ok) throw new Error(`서버 응답 오류: ${res.status}`);
            
            const data = await res.json();
            
            // 3. 백엔드에서 받은 AI의 응답(data.reply)을 화면에 추가
            setMessages(prev => [...prev, { 
                id: Date.now() + 1, 
                sender: 'ai', 
                text: data.reply || "죄송합니다. 응답을 생성하지 못했습니다." 
            }]);
        } catch (error) {
            console.error("Chat Error:", error);
            setMessages(prev => [...prev, { 
                id: Date.now() + 1, 
                sender: 'ai', 
                text: "🤖 서버와 연결할 수 없습니다. 백엔드()가 실행 중인지 확인해주세요!" 
            }]);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <Card className="shadow-sm border-0 rounded-4 overflow-hidden" style={{ height: '600px', display: 'flex', flexDirection: 'column' }}>
            {/* 헤더 */}
            <Card.Header className="bg-white border-0 py-3 text-center">
                <h5 className="fw-bold m-0" style={{ color: '#ff8a3d' }}>🤖 AI 재고 관리 비서</h5>
            </Card.Header>

            {/* 채팅창 몸체 */}
            <Card.Body 
                ref={scrollRef}
                className="bg-light p-3" 
                style={{ overflowY: 'auto', flex: 1, display: 'flex', flexDirection: 'column', gap: '12px' }}
            >
                {messages.map((m) => (
                    <div key={m.id} className={`d-flex ${m.sender === 'user' ? 'justify-content-end' : 'justify-content-start'}`}>
                        <div className={`p-3 rounded-4 shadow-sm ${m.sender === 'user' ? 'bg-primary text-white' : 'bg-white text-dark border'}`} 
                             style={{ maxWidth: '85%', fontSize: '0.95rem', lineHeight: '1.5' }}>
                            {m.text}
                        </div>
                    </div>
                ))}
                {isLoading && (
                    <div className="d-flex justify-content-start ps-2">
                        <Spinner animation="grow" size="sm" variant="warning" />
                    </div>
                )}
            </Card.Body>

            {/* 입력 하단바 */}
            <Card.Footer className="bg-white border-top p-3">
                <Form onSubmit={handleSend}>
                    <InputGroup>
                        <Button 
                            variant={isRecording ? 'danger' : 'outline-secondary'} 
                            onClick={toggleRecording}
                            className="rounded-start-pill px-3"
                        >
                            {isRecording ? '🛑' : '🎙️'}
                        </Button>
                        <Form.Control 
                            type="text" 
                            placeholder={isRecording ? "듣고 있어요..." : "비서에게 질문하기..."} 
                            value={input} 
                            onChange={(e) => setInput(e.target.value)}
                            className="border-secondary-subtle py-2"
                        />
                        <Button type="submit" variant="primary" className="rounded-end-pill px-4 fw-bold" disabled={isLoading}>
                            {isLoading ? '...' : '전송'}
                        </Button>
                    </InputGroup>
                </Form>
            </Card.Footer>
        </Card>
    );
};

export default AiChat;