import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Html5QrcodeScanner } from 'html5-qrcode';
import { useNavigate } from 'react-router-dom'; 
import { Spinner, Card, Button, Badge, Row, Col, Form, ListGroup } from 'react-bootstrap';
import axios from 'axios';

const Scanner = () => {
    const scannerRef = useRef(null);
    const navigate = useNavigate();
    const API_BASE_URL = process.env.REACT_APP_API_URL || "";
    
    const [isProcessing, setIsProcessing] = useState(false);
    const [quickItem, setQuickItem] = useState(null); 
    const [filteredItems, setFilteredItems] = useState([]); // ✅ 이것만 사용하여 경고 해결
    const [selectedLocation, setSelectedLocation] = useState("전체");
    const [selectedCategory, setSelectedCategory] = useState("전체");

    const locations = ["전체", ...JSON.parse(localStorage.getItem('restock_locs') || "[]")];
    const categories = ["전체", ...JSON.parse(localStorage.getItem('restock_cats') || "[]")];

    // 데이터 로드 및 필터링 (불필요한 allInventory 상태 제거)
    const loadAndFilterData = useCallback(async () => {
        try {
            const res = await axios.get(`${API_BASE_URL}/api/inventory`);
            let result = res.data;
            if (selectedLocation !== "전체") result = result.filter(i => i.location === selectedLocation);
            if (selectedCategory !== "전체") result = result.filter(i => i.category === selectedCategory);
            setFilteredItems(result);
        } catch (e) { console.error("데이터 로드 실패"); }
    }, [API_BASE_URL, selectedLocation, selectedCategory]);

    const stopScanner = useCallback(() => {
        if (scannerRef.current) {
            scannerRef.current.clear().catch(err => console.error(err));
            scannerRef.current = null;
        }
    }, []);

    const onScanSuccess = useCallback(async (scannedText) => {
        if (isProcessing) return;
        setIsProcessing(true);
        try {
            const response = await axios.get(`${API_BASE_URL}/api/inventory/search`, {
                params: { qrCode: scannedText.trim() }
            });
            if (response.status === 200 && response.data) {
                setQuickItem(response.data);
                if (selectedLocation === "전체") setSelectedLocation(response.data.location);
            } else {
                if (window.confirm("신규 상품입니다. 등록하시겠습니까?")) {
                    navigate('/inventory/add', { state: { scannedQr: scannedText } });
                }
            }
        } catch (error) {
            if (window.confirm("등록되지 않은 QR입니다. 신규 등록하시겠습니까?")) {
                navigate('/inventory/add', { state: { scannedQr: scannedText } });
            }
        } finally { setIsProcessing(false); }
    }, [API_BASE_URL, isProcessing, selectedLocation, navigate]);

    const initScanner = useCallback(() => {
        if (!scannerRef.current) {
            const qrboxFunction = (vw, vh) => {
                let size = Math.floor(Math.min(vw, vh) * 0.7);
                return { width: Math.max(size, 250), height: Math.max(size, 250) };
            };
            scannerRef.current = new Html5QrcodeScanner("reader", { 
                fps: 10, qrbox: qrboxFunction, aspectRatio: 1.0, rememberLastUsedCamera: true
            }, false);
            scannerRef.current.render(onScanSuccess, () => {});
        }
    }, [onScanSuccess]);

    useEffect(() => {
        loadAndFilterData();
        initScanner();
        return () => stopScanner();
    }, [loadAndFilterData, initScanner, stopScanner]);

    const handleQuickUpdate = async (updatedFields) => {
        const newData = { ...quickItem, ...updatedFields };
        setQuickItem(newData); 
        try {
            await axios.put(`${API_BASE_URL}/api/inventory/${quickItem.id}`, newData);
            loadAndFilterData(); // 즉시 리스트 갱신
        } catch (error) { alert("수정사항 반영 실패"); }
    };

    return (
        <div className="page-content p-4" style={{ backgroundColor: '#fff5ed', minHeight: '100vh' }}>
            <div className="text-center mb-4">
                <h2 className="fw-bold" style={{ color: '#ff8a3d' }}>🥕 재고 실사</h2>
                <p className="text-muted small">구역을 선택하거나 QR을 스캔하여 재고를 보정하세요.</p>
            </div>

            <Card className="mx-auto border-0 shadow-sm rounded-4 mb-4" style={{ maxWidth: '450px' }}>
                <Card.Body className="p-3">
                    <Row className="g-2">
                        <Col xs={6}>
                            <Form.Select size="sm" className="rounded-pill border-light bg-light" 
                                value={selectedLocation} onChange={e => setSelectedLocation(e.target.value)}>
                                {locations.map(l => <option key={l} value={l}>{l}</option>)}
                            </Form.Select>
                        </Col>
                        <Col xs={6}>
                            <Form.Select size="sm" className="rounded-pill border-light bg-light" 
                                value={selectedCategory} onChange={e => setSelectedCategory(e.target.value)}>
                                {categories.map(c => <option key={c} value={c}>{c}</option>)}
                            </Form.Select>
                        </Col>
                    </Row>
                </Card.Body>
            </Card>
            
            <div className="mx-auto position-relative mb-4" style={{ maxWidth: '450px' }}>
                <div id="reader" className="overflow-hidden rounded-4 border-0 shadow-lg"></div>
                {isProcessing && (
                    <div className="position-absolute top-0 start-0 w-100 h-100 d-flex flex-column align-items-center justify-content-center bg-white bg-opacity-75 rounded-4" style={{zIndex: 10}}>
                        <Spinner animation="grow" variant="warning" />
                    </div>
                )}
            </div>

            {quickItem && (
                <Card className="mx-auto border-0 shadow-lg rounded-5 overflow-hidden mb-4 animate__animated animate__fadeInUp" style={{ maxWidth: '450px', borderTop: '5px solid #ff8a3d' }}>
                    <Card.Body className="p-4">
                        <div className="d-flex align-items-center gap-3 mb-3">
                            <img src={`${API_BASE_URL}${quickItem.imageUrl}`} className="rounded-3 border" style={{width: '60px', height: '60px', objectFit: 'cover'}} alt="" />
                            <div className="flex-grow-1">
                                <h6 className="fw-bold mb-0">{quickItem.name}</h6>
                                <Badge bg="warning" text="dark" className="small">현재 점검 중</Badge>
                            </div>
                            <Button variant="link" className="text-decoration-none text-muted p-0" onClick={() => navigate(`/inventory/edit/${quickItem.id}`)}>상세 {'>'}</Button>
                        </div>

                        <div className="d-flex align-items-center justify-content-between my-4 bg-light p-3 rounded-4">
                            <Button variant="white" className="shadow-sm rounded-circle fw-bold" onClick={() => handleQuickUpdate({stock: Math.max(0, quickItem.stock - 1)})}>-</Button>
                            <span className="fs-2 fw-bold" style={{color: '#ff8a3d'}}>{quickItem.stock}</span>
                            <Button variant="warning" className="rounded-circle fw-bold text-white shadow-sm" onClick={() => handleQuickUpdate({stock: quickItem.stock + 1})}>+</Button>
                        </div>

                        <div className="d-flex gap-2">
                            {['정상', '파손', '폐기'].map(s => (
                                <Button key={s} variant={quickItem.status === s ? 'dark' : 'outline-secondary'} className="flex-grow-1 rounded-pill fw-bold py-2" onClick={() => handleQuickUpdate({status: s})}>{s}</Button>
                            ))}
                        </div>
                        <Button variant="warning" className="w-100 rounded-pill mt-4 py-2 fw-bold text-white" style={{backgroundColor: '#ff8a3d', border:'none'}} onClick={() => setQuickItem(null)}>✅ 보정 완료</Button>
                    </Card.Body>
                </Card>
            )}

            <div className="mx-auto" style={{ maxWidth: '450px' }}>
                <h6 className="fw-bold mb-3 px-2">🚩 {selectedLocation} 구역 점검 리스트</h6>
                <ListGroup className="shadow-sm rounded-4 border-0 overflow-hidden">
                    {filteredItems.map(item => (
                        <ListGroup.Item key={item.id} onClick={() => setQuickItem(item)} className="p-3 border-light d-flex justify-content-between align-items-center" style={{cursor: 'pointer', backgroundColor: quickItem?.id === item.id ? '#fff3eb' : 'white'}}>
                            <div className="d-flex align-items-center gap-3">
                                <span style={{fontSize: '1.2rem'}}>{quickItem?.id === item.id ? '📍' : '📦'}</span>
                                <div>
                                    <div className={`fw-bold ${quickItem?.id === item.id ? 'text-orange' : ''}`}>{item.name}</div>
                                    <div className="text-muted small">{item.location} | {item.stock}개</div>
                                </div>
                            </div>
                            <Badge bg={item.status === '정상' ? 'success' : 'danger'} pill>{item.status}</Badge>
                        </ListGroup.Item>
                    ))}
                    {filteredItems.length === 0 && (
                        <ListGroup.Item className="text-center py-4 text-muted">해당 구역에 상품이 없습니다.</ListGroup.Item>
                    )}
                </ListGroup>
            </div>
        </div>
    );
};

export default Scanner;