import React, { useEffect, useState } from 'react';
import { Routes, Route, Link, useLocation, Navigate, useNavigate } from 'react-router-dom';
import { Container, Nav, Button } from 'react-bootstrap';
import Dashboard from './pages/Dashboard';
import Inventory from './pages/Inventory';
import InventoryEdit from './pages/InventoryEdit';
import Inbound from './pages/Inbound';
import Scanner from './pages/Scanner';
import ServiceConfig from './pages/ServiceConfig';
import Login from './pages/Login';
import Signup from './pages/Signup';
import Profile from './pages/Profile';
import AiChat from './pages/AiChat';
import './App.css';

function App() {
  const location = useLocation();
  const navigate = useNavigate();
  const isAuthPage = location.pathname === '/login' || location.pathname === '/signup';
  const token = localStorage.getItem('token');
  
  // 🌙 다크모드 상태 관리
  const [theme, setTheme] = useState(localStorage.getItem('theme') || 'light');
  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem('theme', theme);
  }, [theme]);
  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  // ✅ 핵심 수정: 토큰이 없는데 인증 페이지가 아니라면 즉시 로그인으로 리다이렉트
  // (이 로직이 Routes 안에 <Navigate />와 결합되어 첫 화면을 결정합니다)
  if (!token && !isAuthPage) {
    return <Navigate to="/login" replace />;
  }

  return (
    <div className="app-container">
      {!isAuthPage && (
        <aside className="sidebar">
          <div className="sidebar-logo mb-4">
            <h2 style={{ color: '#ff8a3d', fontWeight: '800' }}>🥕 ReStock</h2>
            <p className="text-muted small">AI 스마트 재고관리 시스템</p>
          </div>
          <Nav className="flex-column gap-2 flex-grow-1">
            <Nav.Link as={Link} to="/" className={location.pathname === '/' ? 'active' : ''}>📊 대시보드</Nav.Link>
            <Nav.Link as={Link} to="/inventory" className={location.pathname.startsWith('/inventory') ? 'active' : ''}>📋 재고 현황</Nav.Link>
            <Nav.Link as={Link} to="/inbound" className={location.pathname === '/inbound' ? 'active' : ''}>📥 신규 입고</Nav.Link>
            <Nav.Link as={Link} to="/scanner" className={location.pathname === '/scanner' ? 'active' : ''}>🔍 QR 스캐너</Nav.Link>
            <Nav.Link as={Link} to="/chat" className={location.pathname === '/chat' ? 'active' : ''}>🤖 AI 챗봇</Nav.Link>
            <div className="menu-divider my-3" style={{ height: '1px', backgroundColor: '#eee' }}></div>
            <p className="px-3 small fw-bold text-muted mb-2" style={{ fontSize: '0.75rem' }}>SYSTEM CONFIG</p>
            <Nav.Link as={Link} to="/services" className={location.pathname === '/services' ? 'active' : ''}>⚙️ 처리 사이트 관리</Nav.Link>
            <Nav.Link onClick={() => { localStorage.removeItem('token'); navigate('/login'); }} className="mt-2 text-danger fw-bold" style={{ cursor: 'pointer' }}>🚪 로그아웃</Nav.Link>
          </Nav>
          
          <div className="mt-3 text-center">
            <Button variant={theme === 'light' ? 'outline-dark' : 'outline-light'} className="rounded-pill px-4 w-100 fw-bold" onClick={toggleTheme}>
               {theme === 'light' ? '🌙 다크 모드 켜기' : '☀️ 라이트 모드 켜기'}
            </Button>
          </div>

          <div className="sidebar-footer mt-4">
            <div className="p-3 bg-light rounded-4 border shadow-sm" style={{cursor:'pointer'}} onClick={()=>navigate('/profile')}>
              <p className="mb-1 small fw-bold" style={{color: 'var(--text-main)'}}>관리자 모드 (수정)</p>
              <p className="mb-0 small text-muted" style={{ fontSize: '0.7rem' }}>admin@carrot.com</p>
            </div>
          </div>
        </aside>
      )}

      <main className="main-content" style={{ marginLeft: isAuthPage ? '0' : '280px', width: isAuthPage ? '100%' : 'calc(100% - 280px)' }}>
        <Container fluid className="py-2">
          <Routes>
            {/* ✅ 토큰이 있으면 Dashboard, 없으면 위 if문에서 이미 /login으로 보냄 */}
            <Route path="/" element={<Dashboard />} />
            <Route path="/inventory" element={<Inventory />} />
            <Route path="/inventory/edit/:id" element={<InventoryEdit />} />
            <Route path="/inbound" element={<Inbound />} />
            <Route path="/scanner" element={<Scanner />} />
            <Route path="/services" element={<ServiceConfig />} />
            <Route path="/chat" element={<AiChat />} />
            <Route path="/profile" element={<Profile />} />
            <Route path="/login" element={<Login />} />
            <Route path="/signup" element={<Signup />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </Container>
      </main>
    </div>
  );
}

export default App;