import React, { useEffect, useState, useCallback } from 'react';
import { Card, Table, Button, Form, Row, Col, Badge } from 'react-bootstrap';
import axios from 'axios';

const ServiceConfig = () => {
    // 백엔드 주소 (경고 해결: 템플릿 리터럴을 올바르게 수정)
    const API_BASE_URL = `${process.env.REACT_APP_API_URL}/api/services`;

    const [services, setServices] = useState([]);
    const [newSite, setNewSite] = useState({ name: '', url: '', type: '기부' });

    // 1. 데이터 가져오기 (useCallback으로 감싸서 의존성 경고 해결)
    const fetchServices = useCallback(async () => {
        try {
            const response = await axios.get(API_BASE_URL);
            setServices(response.data);
        } catch (error) {
            console.error("데이터 로드 실패:", error);
        }
    }, [API_BASE_URL]);

    useEffect(() => {
        fetchServices();
    }, [fetchServices]);

    // 2. 새 사이트 등록
    const handleAdd = async () => {
        if (!newSite.name || !newSite.url) return alert("이름과 URL을 모두 입력해주세요!");
        
        try {
            await axios.post(API_BASE_URL, newSite);
            alert("등록되었습니다.");
            setNewSite({ name: '', url: '', type: '기부' });
            fetchServices(); 
        } catch (error) {
            console.error("등록 실패:", error);
        }
    };

    // 3. 사이트 삭제
    const handleDelete = async (id) => {
        if (!window.confirm("정말 삭제하시겠습니까?")) return;
        
        try {
            await axios.delete(`${API_BASE_URL}/${id}`);
            fetchServices(); 
        } catch (error) {
            console.error("삭제 실패:", error);
        }
    };

    return (
        <div className="p-4" style={{ backgroundColor: '#fcfcfc', minHeight: '100vh' }}>
            <div className="mb-4">
                <h3 className="fw-bold" style={{ color: '#ff8a3d' }}>🔗 처리 사이트 관리</h3>
                <p className="text-muted small">입고 시 선택할 기부/판매/폐기처 목록을 MariaDB에서 관리합니다.</p>
            </div>
            
            <Card className="border-0 shadow-sm rounded-5 p-4 mb-4 bg-white">
                <h6 className="fw-bold mb-3">새 사이트 등록</h6>
                <Row className="g-2">
                    <Col md={2}>
                        <Form.Select
                            className="rounded-4 border-0 bg-light py-2"
                            value={newSite.type}
                            onChange={e => setNewSite({...newSite, type: e.target.value})}
                        >
                            <option>기부</option>
                            <option>판매</option>
                            <option>폐기</option>
                            <option>나눔</option>
                        </Form.Select>
                    </Col>
                    
                    <Col md={3}>
                        <Form.Control
                            placeholder="기관/업체명"
                            className="rounded-4 border-0 bg-light py-2"
                            value={newSite.name}
                            onChange={e => setNewSite({...newSite, name: e.target.value})}
                        />
                    </Col>
                    <Col md={5}>
                        <Form.Control
                            placeholder="URL (https://...)"
                            className="rounded-4 border-0 bg-light py-2"
                            value={newSite.url}
                            onChange={e => setNewSite({...newSite, url: e.target.value})}
                        />
                    </Col>
                  
                    <Col md={2}>
                        <Button
                            className="w-100 rounded-pill border-0 fw-bold py-2 shadow-sm"
                            style={{ backgroundColor: '#ff8a3d', color: 'white' }}
                            onClick={handleAdd}
                        >
                            추가하기
                        </Button>
                    </Col>
                </Row>
            </Card>

            <Card className="border-0 shadow-sm rounded-5 overflow-hidden bg-white">
                <Table hover responsive className="m-0 align-middle">
                    <thead className="bg-light text-muted small">
                        <tr style={{ height: '50px' }}>
                            <th className="ps-4">타입</th>
                            <th>사이트명</th>
                            <th>연결 URL</th>
                            <th className="text-center">관리</th>
                        </tr>
                    </thead>
                    <tbody>
                        {services.map(s => (
                            <tr key={s.id} style={{ height: '70px' }}>
                                <td className="ps-4">
                                    <Badge pill bg="light" className="text-dark border">{s.type}</Badge>
                                </td>
                                <td className="fw-bold text-dark">{s.name}</td>
                                <td className="text-muted small">
                                    <a href={s.url} target="_blank" rel="noopener noreferrer" style={{ textDecoration: 'none', color: 'inherit' }}>
                                        {s.url}
                                    </a>
                                </td>
                                <td className="text-center">
                                    <Button
                                        variant="outline-danger"
                                        size="sm"
                                        className="rounded-pill border-0 px-3"
                                        onClick={() => handleDelete(s.id)}
                                    >
                                        삭제
                                    </Button>
                                </td>
                            </tr>
                        ))}
                        {services.length === 0 && (
                            <tr>
                                <td colSpan="4" className="text-center py-5 text-muted">등록된 사이트가 없습니다.</td>
                            </tr>
                        )}
                    </tbody>
                </Table>
            </Card>
        </div>
    );
};

export default ServiceConfig;